const cfg = global.get('fitflow');

if (!cfg) {
  node.status({ fill: 'red', shape: 'dot', text: '❌ Config belum diset!' });
  msg.payload = '❌ Config belum ada!\n\nBuka tab FuelOS → klik node SET CONFIG → klik ▶';
  return msg;
}

const fields = ['base_url','secret','fonnte_token','fonnte_key','user_id','instr_phone'];
const missing = fields.filter(f => !cfg[f] || cfg[f].startsWith('GANTI'));

if (missing.length > 0) {
  node.status({ fill: 'yellow', shape: 'dot', text: '⚠️ ' + missing.length + ' field belum diisi' });
  msg.payload = '⚠️ Field ini belum diisi:\n' + missing.map(f => '  - ' + f).join('\n') +
    '\n\nBuka node SET CONFIG dan isi nilai yang kosong.';
} else {
  node.status({ fill: 'green', shape: 'dot', text: '✅ Semua config lengkap' });
  msg.payload = '✅ Config lengkap:\n' +
    '  base_url:     ' + cfg.base_url + '\n' +
    '  secret:       ' + cfg.secret.slice(0,8) + '...\n' +
    '  fonnte_token: ' + cfg.fonnte_token.slice(0,8) + '...\n' +
    '  fonnte_key:   ' + cfg.fonnte_key + '\n' +
    '  user_id:      ' + cfg.user_id.slice(0,8) + '...\n' +
    '  instr_phone:  ' + cfg.instr_phone;
}

return msg;

const cfg = global.get('fitflow') || {};
msg.method  = 'GET';
msg.headers = { 'x-webhook-secret': cfg.secret };
msg.url     = cfg.base_url + '/api/webhooks/nodered';
return msg;

const ok = msg.payload && msg.payload.ok === true;
node.status({ fill: ok ? 'green' : 'red', shape: 'dot', text: ok ? '✅ App OK' : '❌ Gagal ' + msg.statusCode });
msg.payload = ok
  ? '✅ FitFlow app terhubung!\n' + JSON.stringify(msg.payload, null, 2)
  : '❌ Gagal (HTTP ' + msg.statusCode + ')\nCek: base_url dan secret di config\n\n' + JSON.stringify(msg.payload, null, 2);
return msg;

const cfg = global.get('fitflow') || {};
msg.method  = 'POST';
msg.headers = { 'Authorization': cfg.fonnte_token };
msg.url     = 'https://api.fonnte.com/device';
msg.payload = JSON.stringify({});
return msg;

const ok = msg.statusCode === 200 && msg.payload && msg.payload.status === true;
node.status({ fill: ok ? 'green' : 'red', shape: 'dot', text: ok ? '✅ Token valid - ' + (msg.payload.name || '') : '❌ Token tidak valid' });
msg.payload = ok
  ? '✅ Token Fonnte valid!
Device: ' + (msg.payload.name || '-') + '
Nomor: ' + (msg.payload.device || '-') + '
Status: ' + (msg.payload.status_device || '-')
  : '❌ Token Fonnte tidak valid
Cek fonnte_token di config

' + JSON.stringify(msg.payload, null, 2);
return msg;

const cfg = global.get('fitflow') || {};

let phone = (cfg.instr_phone || '').replace(/\D/g, '');
if (phone.startsWith('0')) phone = '62' + phone.slice(1);

msg.method  = 'POST';
msg.headers = { 'Authorization': cfg.fonnte_token, 'Content-Type': 'application/json' };
msg.url     = 'https://api.fonnte.com/send';
msg.payload = JSON.stringify({
  target:      phone,
  message:     '🧪 *Test FitFlow Node-RED*\n\nKoneksi Node-RED → Fonnte berhasil! ✅\n\nWaktu: ' + new Date().toLocaleString('id-ID'),
  countryCode: '62'
});
return msg;

const ok = msg.payload && msg.payload.status === true;
node.status({ fill: ok ? 'green' : 'red', shape: 'dot', text: ok ? '✅ WA terkirim!' : '❌ Gagal kirim' });
msg.payload = ok
  ? '✅ WA Test berhasil dikirim!\nCek nomor instruktur - harus ada pesan masuk.'
  : '❌ Gagal kirim WA\nCek fonnte_token dan instr_phone di config\n\n' + JSON.stringify(msg.payload, null, 2);
return msg;

msg.method  = 'POST';
msg.headers = { 'Content-Type': 'application/json' };
msg.url     = 'http://localhost:1880/fitflow/new-registration';
msg.payload = JSON.stringify({
  type:   'INSERT',
  table:  'registrations',
  schema: 'public',
  record: {
    id:               'test-' + Date.now(),
    registrant_name:  'Siti Rahayu (TEST)',
    registrant_phone: '081234567890',
    tier:             'early_bird',
    amount_paid:      150000,
    proof_url:        null,
    payment_status:   'pending',
    event_id:         'event-test',
    created_at:       new Date().toISOString()
  },
  old_record: null
});
return msg;

const ok = msg.payload && msg.payload.ok === true;
node.status({ fill: ok ? 'green' : 'red', shape: 'dot', text: ok ? '✅ Notif terkirim' : '❌ Gagal' });
msg.payload = ok
  ? '✅ Simulasi berhasil!\nCek WA instruktur - harus ada notif pendaftaran masuk.'
  : '❌ Gagal (HTTP ' + msg.statusCode + ')\n\n' + JSON.stringify(msg.payload, null, 2);
return msg;

const cfg = global.get('fitflow') || {};

// ⚙️ GANTI dengan nomor WA kamu - nomor ini yang akan terima balasan AI
const SENDER_PHONE = '6281234567890';

msg.method  = 'POST';
msg.headers = { 'Content-Type': 'application/json' };
msg.url     = 'http://localhost:1880/fitflow/wa-incoming';
msg.payload = JSON.stringify({
  device:        '628000000001',
  sender:        SENDER_PHONE,
  message:       'Halo kak, ada kelas zumba jam berapa ya minggu ini?',
  name:          'Member Test',
  id:            'msg_test_' + Date.now(),
  instructor_id: cfg.user_id
});
return msg;

const ok = msg.payload && msg.payload.ok === true;
node.status({ fill: ok ? 'green' : 'red', shape: 'dot', text: ok ? '✅ Bot diproses' : '❌ Gagal' });
msg.payload = ok
  ? '✅ Pesan diterima bot!\nAI sedang proses... balasan WA akan datang ke SENDER_PHONE dalam beberapa detik.'
  : '❌ Gagal (HTTP ' + msg.statusCode + ')\n\n' + JSON.stringify(msg.payload, null, 2);
return msg;
